Rule.Source:
  
  import org.json.JSONArray;
  import org.json.JSONObject;
  import sailpoint.object.Identity;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.lang.StringUtils;

  private static Log logger = LogFactory.getLog("sailpoint.services.asc.Gsuite");

  public String returnValue(Object value){
    if(void == value || value == null){
      return "";
    }
    else{
      return value.toString();
    }
  }

  List adrList = new ArrayList();
  String addressDelimiter = ", ";

  JSONObject json = new JSONObject();
  
  String streetAddress = returnValue(identity.getAttribute("streetAddress"));
  String locality = returnValue(identity.getAttribute("city"));
  String region = returnValue(identity.getAttribute("st"));
  String postOfficeBox = returnValue(identity.getAttribute("postOfficeBox"));
  String postalCode = returnValue(identity.getAttribute("postalCode"));
  String formatted = "";

  if(!StringUtils.isEmpty(streetAddress)){
    formatted = formatted + streetAddress + addressDelimiter;
  }
  if(!StringUtils.isEmpty(postOfficeBox)){
    formatted = formatted + postOfficeBox + addressDelimiter;
  }
  if(!StringUtils.isEmpty(locality)){
    formatted = formatted + locality + addressDelimiter;
  }
  if(!StringUtils.isEmpty(region)){
    formatted = formatted + region + addressDelimiter;
  }
  if(!StringUtils.isEmpty(postalCode)){
    formatted = formatted + postalCode;
  }

  if(!StringUtils.isEmpty(streetAddress)){
    json.put("type", "work");
    json.put("primary", "true");
    json.put("sourceIsStructured", "false");

    json.put("streetAddress", streetAddress);
    
    if (!StringUtils.isEmpty(locality)) {
      json.put("locality", locality);
    }
    
    if (!StringUtils.isEmpty(region)) {
      json.put("region", region);
    }
  
    if (!StringUtils.isEmpty(postOfficeBox)) {
      json.put("poBox", postOfficeBox);
    }
  
    json.put("formatted", formatted);
    
    adrList.add(json.toString());
  }

  if(logger.isDebugEnabled()) logger.debug(" adrList:" + adrList);
    
  return adrList;
